// Parseia texto extraído do PDF ou texto direto do WhatsApp
const txt = $input.first().json.text || $input.first().json.body || '';

const get = (patterns, t) => {
  for (const p of patterns) {
    const m = t.match(p);
    if (m && m[1]) return m[1].trim();
  }
  return null;
};

const nome_cliente   = get([/CLIENTE[:\s]+([^\n]+)/i, /nome[:\s]+([^\n]+)/i], txt);
const numero_venda   = get([/VENDA[:\s]+([^\n]+)/i, /pedido[:\s]+([^\n]+)/i], txt);
const codigo_produto = get([/C[ÓO]DIGO[:\s]+([^\n]+)/i, /SKU[:\s]+([^\n]+)/i], txt);
const nome_produto   = get([/PRODUTO[:\s]+([^\n]+)/i, /item[:\s]+([^\n]+)/i], txt);
const marca          = get([/MARCA[:\s]+([^\n]+)/i], txt);
const quantidade     = get([/QUANTIDADE[:\s]+([^\n]+)/i, /QTD[:\s]+([^\n]+)/i], txt);
const etiqueta_ml    = get([/etiqueta[:\s]+([^\n]+)/i, /\b((?:ML|BR)[0-9A-Z]{8,})\b/i], txt);

const dateMatch = txt.match(/(?:prazo|despachar?(?:\s+em)?|até)[:\s]*(\d{1,2}[\/\-]\d{1,2}(?:[\/\-]\d{2,4})?)/i);
let data_despacho = null;
if (dateMatch) {
  const parts = dateMatch[1].split(/[\/\-]/);
  if (parts.length >= 2) {
    const year = parts[2] ? (parts[2].length === 2 ? '20' + parts[2] : parts[2]) : new Date().getFullYear();
    data_despacho = `${year}-${parts[1].padStart(2,'0')}-${parts[0].padStart(2,'0')}`;
  }
}

const id = `id-${Date.now()}-${Math.random().toString(36).slice(2)}`;

return [{
  json: {
    id,
    created_at: new Date().toISOString(),
    updated_at: new Date().toISOString(),
    nome_cliente: nome_cliente || 'Não identificado',
    numero_venda,
    codigo_produto: codigo_produto ? codigo_produto.toUpperCase() : null,
    nome_produto,
    marca,
    quantidade,
    etiqueta_ml,
    data_despacho,
    status: 'recebido',
    observacoes: null,
    galpao: null
  }
}];

